from pathlib import Path

patterns=[
    b"-----BEGIN RSA PRIVATE KEY-----",
    b"-----BEGIN PRIVATE KEY-----",
    b"-----BEGIN EC PRIVATE KEY-----",
]

allowed_padding={0, 0x0a, 0x0d}

def match_with_padding(data, idx, pattern):
    i=idx
    for ch in pattern:
        if i>=len(data):
            return -1
        byte=data[i]
        if byte==ch:
            i+=1
            continue
        # skip padding bytes
        while byte in allowed_padding:
            i+=1
            if i>=len(data):
                return -1
            byte=data[i]
        if byte==ch:
            i+=1
            continue
        return -1
    return i

for fname in ['heartbleed_leak.bin', 'heartbleed_leak_old.bin', 'heartbleed_random_leak.bin']:
    path=Path('/ctf-workspace')/fname
    if not path.exists():
        continue
    data=path.read_bytes()
    print(f"Analyzing {fname} (size {len(data)})")
    for pat in patterns:
        pat_len=len(pat)
        for idx in range(len(data)):
            if data[idx] not in (pat[0],):
                continue
            end=match_with_padding(data, idx, pat)
            if end!=-1:
                start=max(0, idx-60)
                print(f"Pattern {pat.decode()} found at {idx}")
                snippet=data[start:start+pat_len+120]
                print(snippet.decode('latin1', errors='ignore'))
                raise SystemExit
print('No padded PEM delimiters found')
